"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Menu, X, LogOut, LogIn } from "lucide-react";
import { useAuth } from "@/context/AuthContext";

const baseNavLinks = [
  { name: "Home",     href: "/" },
  { name: "About Us", href: "/about" },
  { name: "Menu",     href: "/menu" },
  { name: "Insights", href: "/insights" },
  { name: "Contact",  href: "/contact" },
];

export default function Navbar() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const { role, logout } = useAuth();
  const router = useRouter();

  // Only admins can see Orders
  const navLinks = role === "admin"
    ? [...baseNavLinks, { name: "Orders", href: "/orders" }]
    : baseNavLinks;

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    router.push("/");
  };

  return (
    <>
      {/* ── Main nav bar ── */}
      <motion.nav
        initial={{ y: -80 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.5, ease: "easeOut" }}
        className="nav-root"
        style={{ zIndex: "var(--z-nav)" }}
      >
        <div className="nav-inner">
          {/* Logo */}
          <Link href="/" className="nav-logo">
            <div className="nav-logo-circle">
              <span style={{ color: "var(--color-gold)", fontFamily: "'Cormorant Garamond', serif", fontSize: "20px", fontWeight: 600 }}>
                A
              </span>
            </div>
            <div>
              <span style={{ color: "var(--color-text)", fontFamily: "'Cormorant Garamond', serif", fontSize: "20px", letterSpacing: "0.08em" }}>
                Aurora
              </span>
              <span style={{ display: "block", color: "rgba(201, 169, 110, 0.7)", fontSize: "9px", letterSpacing: "0.3em", textTransform: "uppercase", marginTop: "-2px" }}>
                Dining
              </span>
            </div>
          </Link>

          {/* Desktop nav links */}
          <nav className="nav-links nav-reserve-desktop" style={{ display: "flex", alignItems: "center", gap: "40px" }}>
            {navLinks.map((link) => (
              <Link
                key={link.name}
                href={link.href}
                className="nav-link animated-underline"
              >
                {link.name}
              </Link>
            ))}

            {/* Auth actions */}
            {role === "admin" && (
              <span className="nav-role-badge nav-role-admin">Admin</span>
            )}
            {role === "customer" && (
              <span className="nav-role-badge nav-role-customer">Guest</span>
            )}

            {role ? (
              <button onClick={handleLogout} className="nav-logout-btn" aria-label="Logout">
                <LogOut size={15} />
                <span>Logout</span>
              </button>
            ) : (
              <Link href="/login" className="nav-reserve">
                Login
              </Link>
            )}

            <Link href="/contact" className="nav-reserve">
              Reserve
            </Link>
          </nav>

          {/* Mobile hamburger */}
          <button
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label="Toggle menu"
            style={{
              display: "none",
              background: "transparent",
              border: "none",
              color: "var(--color-text)",
              cursor: "pointer",
              padding: "8px",
              transition: "color 0.2s",
            }}
            className="mobile-menu-btn"
          >
            {mobileOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>

        {/* Inline style to show hamburger on tablet/mobile */}
        <style>{`
          @media (max-width: 1024px) {
            .nav-links.nav-reserve-desktop { display: none !important; }
            .mobile-menu-btn { display: flex !important; }
          }
        `}</style>
      </motion.nav>

      {/* ── Mobile full-screen menu ── */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, y: -16 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -16 }}
            transition={{ duration: 0.25 }}
            style={{
              position: "fixed",
              inset: 0,
              top: "80px",
              zIndex: 99,
              backgroundColor: "rgba(10, 10, 10, 0.98)",
              backdropFilter: "blur(24px)",
              padding: "32px 24px",
              display: "flex",
              flexDirection: "column",
              gap: "8px",
              overflowY: "auto",
              overscrollBehavior: "contain",
            }}
          >
            {navLinks.map((link, i) => (
              <motion.div
                key={link.name}
                initial={{ opacity: 0, x: -24 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.06 }}
              >
                <Link
                  href={link.href}
                  onClick={() => setMobileOpen(false)}
                  style={{
                    display: "block",
                    padding: "16px 0",
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: "28px",
                    fontWeight: 300,
                    color: "var(--color-text)",
                    textDecoration: "none",
                    borderBottom: "1px solid var(--color-border)",
                    transition: "color 0.2s",
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.color = "var(--color-gold)")}
                  onMouseLeave={(e) => (e.currentTarget.style.color = "var(--color-text)")}
                >
                  {link.name}
                </Link>
              </motion.div>
            ))}

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.45 }}
              style={{ marginTop: "32px", display: "flex", flexDirection: "column", gap: "12px" }}
            >
              {/* Role pill */}
              {role && (
                <span style={{
                  display: "inline-block",
                  fontSize: "10px",
                  letterSpacing: "0.2em",
                  textTransform: "uppercase",
                  color: "var(--color-gold)",
                  border: "1px solid rgba(201,169,110,0.4)",
                  borderRadius: "4px",
                  padding: "4px 12px",
                  width: "fit-content",
                }}>
                  {role === "admin" ? "🛡 Admin" : "👤 Guest"}
                </span>
              )}

              {role ? (
                <button
                  onClick={handleLogout}
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    gap: "8px",
                    background: "transparent",
                    border: "1px solid rgba(201,169,110,0.4)",
                    color: "var(--color-gold)",
                    padding: "12px 24px",
                    borderRadius: "4px",
                    cursor: "pointer",
                    fontSize: "11px",
                    letterSpacing: "0.15em",
                    textTransform: "uppercase",
                    fontFamily: "'Jost', sans-serif",
                    width: "fit-content",
                  }}
                >
                  <LogOut size={14} /> Logout
                </button>
              ) : (
                <Link
                  href="/login"
                  onClick={() => setMobileOpen(false)}
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    gap: "8px",
                    color: "var(--color-gold)",
                    border: "1px solid var(--color-gold)",
                    padding: "12px 24px",
                    borderRadius: "4px",
                    fontSize: "11px",
                    letterSpacing: "0.15em",
                    textTransform: "uppercase",
                    fontFamily: "'Jost', sans-serif",
                    width: "fit-content",
                    textDecoration: "none",
                  }}
                >
                  <LogIn size={14} /> Login
                </Link>
              )}

              <Link
                href="/contact"
                onClick={() => setMobileOpen(false)}
                className="nav-reserve"
                style={{ display: "inline-block" }}
              >
                Reserve a Table
              </Link>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
